import{_ as a,o as t,c as n,a2 as s}from"./chunks/framework.ufzXw1qY.js";const u=JSON.parse('{"title":"SIN-Zeus — Fleet Commander","description":"","frontmatter":{},"headers":[],"relativePath":"governance/zeus.md","filePath":"governance/zeus.md"}'),r={name:"governance/zeus.md"};function o(i,e,l,d,c,h){return t(),n("div",null,[...e[0]||(e[0]=[s(`<h1 id="sin-zeus-—-fleet-commander" tabindex="-1">SIN-Zeus — Fleet Commander <a class="header-anchor" href="#sin-zeus-—-fleet-commander" aria-label="Permalink to &quot;SIN-Zeus — Fleet Commander&quot;">​</a></h1><p><strong>Role:</strong> Fleet Commander &amp; Control-Plane Orchestrator <strong>Model:</strong> <code>qwen/coder-model</code> (primary), <code>claude-opus-4.6-thinking</code> (fallback) <strong>Status:</strong> Active <strong>Owner:</strong> OpenSIN-AI control-plane governance</p><hr><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>SIN-Zeus is the top-level orchestrator of the OpenSIN-AI fleet. It conducts organization-wide audits, dispatches tasks to team managers, enforces governance compliance, and maintains the SSOT (Single Source of Truth) across all repositories.</p><hr><h2 id="responsibilities" tabindex="-1">Responsibilities <a class="header-anchor" href="#responsibilities" aria-label="Permalink to &quot;Responsibilities&quot;">​</a></h2><h3 id="_1-organization-audits" tabindex="-1">1. Organization Audits <a class="header-anchor" href="#_1-organization-audits" aria-label="Permalink to &quot;1. Organization Audits&quot;">​</a></h3><ul><li>Scans all repos for stale branches, open issues, fake PRs</li><li>Creates tracking projects on GitHub</li><li>Generates audit reports with findings and action items</li><li>Closes resolved issues and stale PRs</li></ul><h3 id="_2-task-dispatch" tabindex="-1">2. Task Dispatch <a class="header-anchor" href="#_2-task-dispatch" aria-label="Permalink to &quot;2. Task Dispatch&quot;">​</a></h3><ul><li>Delegates work to Team Managers (Coding, Worker, Infra, Google, Microsoft)</li><li>Uses background agents for parallel execution</li><li>Monitors task completion and retries on failure</li></ul><h3 id="_3-governance-enforcement" tabindex="-1">3. Governance Enforcement <a class="header-anchor" href="#_3-governance-enforcement" aria-label="Permalink to &quot;3. Governance Enforcement&quot;">​</a></h3><ul><li>Runs Repo Health Check compliance audits</li><li>Monitors PR-Watcher results</li><li>Enforces mandate priorities (P-100 to P0)</li><li>Bans and flags protocol violations</li></ul><h3 id="_4-fleet-coordination" tabindex="-1">4. Fleet Coordination <a class="header-anchor" href="#_4-fleet-coordination" aria-label="Permalink to &quot;4. Fleet Coordination&quot;">​</a></h3><ul><li>Maintains fleet registry and team configurations</li><li>Coordinates cross-team collaboration</li><li>Manages the Fleet Operations project board</li><li>Handles incident escalation</li></ul><hr><h2 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────┐</span></span>
<span class="line"><span>│           SIN-Zeus                   │</span></span>
<span class="line"><span>│     (Fleet Commander)                │</span></span>
<span class="line"><span>├──────────────┬──────────────────────┤</span></span>
<span class="line"><span>│   Scan       │  Audit               │</span></span>
<span class="line"><span>│   ├──repos   │  ├──issues           │</span></span>
<span class="line"><span>│   ├──branches│  ├──PRs              │</span></span>
<span class="line"><span>│   └──config  │  └──compliance       │</span></span>
<span class="line"><span>│              │                      │</span></span>
<span class="line"><span>│   Dispatch   │  Report              │</span></span>
<span class="line"><span>│   ├──teams   │  ├──GitHub Issues    │</span></span>
<span class="line"><span>│   ├──agents  │  ├──Project Boards   │</span></span>
<span class="line"><span>│   └──tasks   │  └──Audit Reports    │</span></span>
<span class="line"><span>└──────────────┴──────────────────────┘</span></span></code></pre></div><hr><h2 id="commands" tabindex="-1">Commands <a class="header-anchor" href="#commands" aria-label="Permalink to &quot;Commands&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Command</th><th>Description</th></tr></thead><tbody><tr><td><code>zeus.audit</code></td><td>Full organization audit across all repos</td></tr><tr><td><code>zeus.dispatch</code></td><td>Delegate task to team fleet</td></tr><tr><td><code>zeus.compliance</code></td><td>Run governance compliance check</td></tr><tr><td><code>zeus.health</code></td><td>Fleet health status report</td></tr><tr><td><code>zeus.cleanup</code></td><td>Prune stale branches, close resolved issues</td></tr></tbody></table><hr><h2 id="recent-actions" tabindex="-1">Recent Actions <a class="header-anchor" href="#recent-actions" aria-label="Permalink to &quot;Recent Actions&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Date</th><th>Action</th><th>Result</th></tr></thead><tbody><tr><td>2026-04-14</td><td>Org-wide audit</td><td>22 stale branches pruned, 1 fake PR closed, 3 zombie issues closed</td></tr><tr><td>2026-04-14</td><td>Fleet Project #21 created</td><td>19 issues tracked</td></tr><tr><td>2026-04-14</td><td>Audit Issue #99 created</td><td>Complete findings documented</td></tr></tbody></table><hr><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/governance/hermes.html">Hermes — Task Dispatcher</a></li><li><a href="/governance/overview.html">Governance Overview</a></li><li><a href="/fleet/overview.html">Fleet Overview</a></li><li><a href="/governance/repo-health-check.html">Repo Health Check</a></li></ul><hr><h2 id="relevante-mandate" tabindex="-1">Relevante Mandate <a class="header-anchor" href="#relevante-mandate" aria-label="Permalink to &quot;Relevante Mandate&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Mandat</th><th>Priority</th><th>Regel</th></tr></thead><tbody><tr><td><strong>Immediate Bug Registry</strong></td><td>-4.0</td><td>JEDER Bug SOFORT als GitHub Issue</td></tr><tr><td><strong>PR-Watcher</strong></td><td>0.0</td><td>Alle Repos brauchen PR-Watcher</td></tr><tr><td><strong>Zeus/Hermes</strong></td><td>0.0</td><td>Fleet-Kommando via SIN-Zeus</td></tr></tbody></table><p>→ <a href="/best-practices/error-handling.html">Alle Mandate</a></p>`,31)])])}const m=a(r,[["render",o]]);export{u as __pageData,m as default};
